+// reloadOutcome is intentionally kept independent of the web package so the
+// reload coordinator can persist exactly the object exposed by the API.
+type reloadOutcome struct {
+	LastReloadID         string             `json:"last_reload_id"`
+	LastReloadSuccessful bool               `json:"last_reload_successful"`
+	ErrorCategory        string             `json:"error_category"`
+	ErrorMessage         string             `json:"error_message"`
+	AppliedReloaders     []string           `json:"applied_reloaders"`
+	RollbackAttempted    bool               `json:"rollback_attempted"`
+	RollbackSuccessful   bool               `json:"rollback_successful"`
+	FailedReloader       string             `json:"failed_reloader"`
+	ReloaderTimingsMS    map[string]float64 `json:"reloader_timings_ms"`
+}
+
+type transactionalReloadState struct {
+	mu       sync.RWMutex
+	enabled  bool
+	filename string
+	logger   *slog.Logger
+	lastGood *config.Config
+	outcome  reloadOutcome
+}
+
+func newTransactionalReloadState(enabled bool, filename string, logger *slog.Logger) *transactionalReloadState {
+	s := &transactionalReloadState{enabled: enabled, filename: filename, logger: logger, outcome: emptyReloadOutcome()}
+	if !enabled {
+		return s
+	}
+	b, err := os.ReadFile(filename)
+	if err != nil {
+		if !errors.Is(err, os.ErrNotExist) {
+			logger.Warn("Unable to read persisted reload status", "err", err)
+		}
+		return s
+	}
+	var outcome reloadOutcome
+	if err := json.Unmarshal(b, &outcome); err != nil {
+		logger.Warn("Unable to decode persisted reload status", "err", err)
+		return s
+	}
+	if outcome.AppliedReloaders == nil {
+		outcome.AppliedReloaders = []string{}
+	}
+	if outcome.ReloaderTimingsMS == nil {
+		outcome.ReloaderTimingsMS = map[string]float64{}
+	}
+	s.outcome = outcome
+	return s
+}
+
+func emptyReloadOutcome() reloadOutcome {
+	return reloadOutcome{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}
+}
+
+func (s *transactionalReloadState) Status() any {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.outcome
+}
+
+func (s *transactionalReloadState) setLastGood(conf *config.Config) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
+	s.lastGood = conf
+}
+
+func (s *transactionalReloadState) recordLoadError(err error) {
+	s.record(reloadOutcome{
+		LastReloadID:      time.Now().UTC().Format(time.RFC3339Nano),
+		ErrorCategory:     "load_error",
+		ErrorMessage:      err.Error(),
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]float64{},
+	})
+}
+
+func (s *transactionalReloadState) apply(conf *config.Config, rls []reloader) error {
+	outcome := emptyReloadOutcome()
+	outcome.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = float64(time.Since(start)) / float64(time.Millisecond)
+		if err == nil {
+			outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+			continue
+		}
+
+		outcome.ErrorCategory = "apply_error"
+		outcome.ErrorMessage = err.Error()
+		outcome.FailedReloader = rl.name
+		if len(outcome.AppliedReloaders) > 0 {
+			outcome.RollbackAttempted = true
+			outcome.RollbackSuccessful = s.rollback(rls, &outcome)
+			if !outcome.RollbackSuccessful {
+				outcome.ErrorCategory = "rollback_error"
+			}
+		}
+		s.record(outcome)
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, err)
+	}
+	outcome.LastReloadSuccessful = true
+	s.record(outcome)
+	return nil
+}
+
+func (s *transactionalReloadState) rollback(rls []reloader, outcome *reloadOutcome) bool {
+	s.mu.RLock()
+	lastGood := s.lastGood
+	s.mu.RUnlock()
+	if lastGood == nil {
+		outcome.ErrorMessage += "; no last known-good configuration is available for rollback"
+		return false
+	}
+	for _, rl := range rls {
+		if err := rl.reloader(lastGood); err != nil {
+			outcome.ErrorMessage += fmt.Sprintf("; rollback reloader %q failed: %v", rl.name, err)
+			return false
+		}
+	}
+	return true
+}
+
+func (s *transactionalReloadState) record(outcome reloadOutcome) {
+	s.mu.Lock()
+	s.outcome = outcome
+	s.mu.Unlock()
+
+	b, err := json.Marshal(outcome)
+	if err != nil {
+		s.logger.Error("Unable to encode reload status", "err", err)
+		return
+	}
+	if err := os.MkdirAll(filepath.Dir(s.filename), 0o755); err != nil {
+		s.logger.Error("Unable to create reload status directory", "err", err)
+		return
+	}
+	tmp := s.filename + ".tmp"
+	if err := os.WriteFile(tmp, b, 0o644); err != nil {
+		s.logger.Error("Unable to persist reload status", "err", err)
+		return
+	}
+	if err := os.Rename(tmp, s.filename); err != nil {
+		s.logger.Error("Unable to finalize reload status", "err", err)
+	}
+}
