+
+func newTransactionalReloadState(enabled bool, filename string, logger *slog.Logger) *transactionalReloadState {
+	s := &transactionalReloadState{enabled: enabled, filename: filename, logger: logger, outcome: emptyReloadOutcome()}
+	if !enabled {
