+func emptyReloadOutcome() reloadOutcome {
+	return reloadOutcome{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]float64{}}
+}
+
+func (s *transactionalReloadState) Status() any {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	return s.outcome
+}
+
+func (s *transactionalReloadState) setLastGood(conf *config.Config) {
+	s.mu.Lock()
+	defer s.mu.Unlock()
